const day = new Date().getDay();
const types = { 1: 'pain_point', 3: 'case_study', 5: 'tips' };
const type = types[day] || 'pain_point';
const prompts = {
  pain_point: { type: 'pain_point', instruction: 'Write a LinkedIn post (150-200 words) for AutoShop SMS AI targeting auto repair shop owners. Focus on the PAIN POINT of missed calls costing shops real revenue. Include a specific stat or scenario (e.g. The average missed call costs an auto shop $250-$700 in lost repair revenue). Tone: professional, empathetic, solution-oriented. Do NOT be salesy. End with a soft CTA mentioning autoshopsmsai.com. Use 2-3 relevant hashtags at the end. No emojis in the first line.' },
  case_study: { type: 'case_study', instruction: 'Write a LinkedIn post (150-200 words) for AutoShop SMS AI in a case-study style. Share realistic stats about how AI-powered SMS booking helps auto repair shops. Use a narrative format. Tone: credible, data-informed, conversational. End with a soft CTA mentioning autoshopsmsai.com. Use 2-3 relevant hashtags at the end. No emojis in the first line.' },
  tips: { type: 'tips', instruction: 'Write a LinkedIn post (150-200 words) for AutoShop SMS AI offering practical advice to auto repair shop owners. Share 3 actionable tips about improving customer communication, reducing no-shows, or capturing more revenue from inbound calls. Tone: helpful, expert, peer-to-peer. End with a soft mention of autoshopsmsai.com as a resource. Use 2-3 relevant hashtags at the end. No emojis in the first line.' }
};
return [{ json: prompts[type] }];

const resp = $input.first().json;
let postText = '';
if (resp.content && resp.content[0] && resp.content[0].text) {
  postText = resp.content[0].text.trim();
} else {
  throw new Error('Claude API error: ' + JSON.stringify(resp).slice(0, 500));
}
const postType = $('Select Post Type').first().json.type;
return [{ json: { postText, postType, generatedAt: new Date().toISOString() } }];

const resp = $input.first().json;
const post = $('Extract Post Text').first().json;
let dalleUrl = '';
if (resp.data && resp.data[0] && resp.data[0].url) {
  dalleUrl = resp.data[0].url;
}
return [{ json: { dalleUrl, postText: post.postText, postType: post.postType, generatedAt: post.generatedAt } }];

const d = $('Extract DALL-E URL').first().json;
const tg = $input.first().json;
let tgFileId = '';
if (tg.ok && tg.result && tg.result.photo) {
  const photos = tg.result.photo;
  tgFileId = photos[photos.length - 1].file_id;
}
return [{ json: {
  postText: d.postText,
  postType: d.postType,
  generatedAt: d.generatedAt,
  imageUrl: tgFileId || d.dalleUrl,
  status: 'pending_review'
} }];

const data = $('Merge Post + Image').first().json;
const execId = $execution.id;
const base = 'https://bandomasis.app.n8n.cloud/webhook-waiting/' + execId;

const labels = { pain_point: 'Pain Point', case_study: 'Case Study', tips: 'Tips & Advice' };

let msg = 'LINKEDIN POST READY FOR REVIEW\n\n';
msg += 'Type: ' + (labels[data.postType] || data.postType) + '\n';
msg += 'Generated: ' + data.generatedAt + '\n\n';
msg += '--- FULL POST ---\n';
msg += data.postText + '\n';
msg += '--- END ---\n\n';
msg += 'APPROVE:\n' + base + '?action=approve\n\n';
msg += 'SKIP:\n' + base + '?action=skip';

return [{ json: { chatId: '8747048300', text: msg } }];

const resp = $input.first().json;
const success = !!resp.id;
const msg = success
  ? 'LinkedIn post published! Post ID: ' + resp.id
  : 'LinkedIn post FAILED: ' + JSON.stringify(resp).slice(0, 500);
return [{ json: { chatId: '8747048300', text: msg, success } }];
